class Solution {
    public int[] separateDigits(int[] nums) {
        int[] result = new int[nums.length * String.valueOf(Math.max(1, nums[nums.length - 1])).length()];
        for (int num : nums) {
            String str = String.valueOf(num);
            for (int i = 0; i < str.length(); i++) {
                result[i + str.length() * (nums.length - 1 - nums.indexOf(num))] = str.charAt(i) - '0';
            }
        }
        return result;
    }
}
